class Solution {
public:
    int minSwaps(string s) {
        int n = s.length();
        int openCount = 0;
        int swaps = 0;
        for (int i = 0; i < n; i++) {
            if (s[i] == '[') {
                openCount++;
            } else {
                openCount--;
            }
            if (openCount < 0) {
                swaps++;
                openCount++;
            }
        }
        return swaps;
    }
};
```
